// EndpointRegenerator handles the regeneration of all endpoints managed by
// the endpoint manager. It provides regeneration-specific functionality
// separately from endpoint lifecycle management.
type EndpointRegenerator struct {
	getEndpoints func() []*Endpoint
}

// NewEndpointRegenerator creates a new EndpointRegenerator that retrieves
// endpoints using the provided function.
func NewEndpointRegenerator(getEndpoints func() []*Endpoint) *EndpointRegenerator {
	return &EndpointRegenerator{getEndpoints: getEndpoints}
}

// RegenerateAllEndpoints calls a setState for each endpoint and regenerates if
// state transaction is valid. Returns a WaitGroup that is signaled once all
// endpoints have been regenerated.
func (r *EndpointRegenerator) RegenerateAllEndpoints(regenMetadata *regeneration.ExternalRegenerationMetadata) *sync.WaitGroup {
	var wg sync.WaitGroup

	eps := r.getEndpoints()
	wg.Add(len(eps))

	// Dereference "reason" field outside of logging statement; see
	// https://github.com/sirupsen/logrus/issues/1003.
	reason := regenMetadata.Reason
	log.WithFields(logrus.Fields{"reason": reason}).Info("regenerating all endpoints")
	for _, ep := range eps {
		go func(ep *Endpoint) {
			<-ep.RegenerateIfAlive(regenMetadata)
			wg.Done()
		}(ep)
	}

	return &wg
}

